import React from 'react';
import { useVideoConfig } from 'remotion';
import { PlacementBox, resolveSize } from '../../../lib/canvas';
import { Surface } from '../../../lib/primitives';
import { useStaggeredEntrance } from '../../../lib/hooks';
import { bentoGridSchema, type BentoGridProps } from './schema';

export { bentoGridSchema, type BentoGridProps };

/**
 * A data-driven bento layout — a CSS grid of glass `Surface` cards with varying
 * column/row spans. Each cell rises + fades in on the house spring, staggered
 * left-to-right so the grid assembles as one calm cascade rather than popping
 * all at once. Pass `items` to drive the content; the one `accent` cell earns
 * the rose. Self-contained except the shared `Surface` primitive and the
 * `useStaggeredEntrance` hook.
 *
 * @example
 * <BentoGrid placement="center" />
 */
export const BentoGrid: React.FC<BentoGridProps> = ({
  items,
  columns,
  gap,
  width,
  padding,
  delay,
  stagger,
  fontSize,
  size,
  color,
  captionColor,
  accentColor,
  fontFamily,
  placement,
}) => {
  const { width: canvasW, height: canvasH } = useVideoConfig();
  const resolvedFontSize = size ? resolveSize(size, { width: canvasW, height: canvasH }) : fontSize;
  // One hook call, then a per-index entrance — never a hook in a loop.
  const at = useStaggeredEntrance({ type: 'rise', delay, increment: stagger });

  return (
    <PlacementBox placement={placement}>
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: `repeat(${columns}, 1fr)`,
          gridAutoRows: '1fr',
          gap,
          width,
        }}
      >
        {items.map((item, i) => {
          const entrance = at(i);
          const colSpan = Math.min(item.colSpan, columns);
          return (
            <div
              key={i}
              style={{
                gridColumn: `span ${colSpan}`,
                gridRow: `span ${item.rowSpan}`,
                opacity: entrance.opacity,
                transform: entrance.transform,
              }}
            >
              <Surface
                variant="glass"
                padding={padding}
                height="100%"
                borderColor={item.accent ? accentColor : undefined}
              >
                <div
                  style={{
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'flex-end',
                    height: '100%',
                    gap: 8,
                  }}
                >
                  {item.value && (
                    <div
                      style={{
                        color: item.accent ? accentColor : color,
                        fontFamily,
                        fontSize: resolvedFontSize * 1.8,
                        fontWeight: 600,
                        letterSpacing: '-0.03em',
                        lineHeight: 1,
                      }}
                    >
                      {item.value}
                    </div>
                  )}
                  <div
                    style={{
                      color,
                      fontFamily,
                      fontSize: resolvedFontSize,
                      fontWeight: 600,
                      letterSpacing: '-0.02em',
                      lineHeight: 1.1,
                    }}
                  >
                    {item.title}
                  </div>
                  {item.caption && (
                    <div
                      style={{
                        color: captionColor,
                        fontFamily: 'var(--onda-font-body, "Space Grotesk", sans-serif)',
                        fontSize: Math.round(resolvedFontSize * 0.56),
                        lineHeight: 1.45,
                      }}
                    >
                      {item.caption}
                    </div>
                  )}
                </div>
              </Surface>
            </div>
          );
        })}
      </div>
    </PlacementBox>
  );
};

export default BentoGrid;

import { z } from 'zod';
import { placementSchema, sizeRoleSchema } from '../../../lib/canvas-schemas';

/** A single bento cell. Spans default to 1×1; `accent` earns the rose tint. */
export const bentoItemSchema = z.object({
  /** Cell title (display font). */
  title: z.string(),
  /** Optional headline figure shown large above the title (e.g. `'98%'`). Empty hides it. */
  value: z.string().optional(),
  /** Optional caption beneath the title. Empty hides it. */
  caption: z.string().optional(),
  /** Columns this cell spans. Clamped to the grid's `columns`. */
  colSpan: z.number().int().min(1).default(1),
  /** Rows this cell spans. */
  rowSpan: z.number().int().min(1).default(1),
  /** Marks the one earned-accent cell — rose value + accent border. Use sparingly. */
  accent: z.boolean().default(false),
});

/** Inferred type for a single {@link BentoGrid} cell. */
export type BentoItem = z.infer<typeof bentoItemSchema>;

/** Zod schema for {@link BentoGrid} props. */
export const bentoGridSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('bento-grid').default('bento-grid'),
  /** The cells, laid out left-to-right, top-to-bottom. Spans drive the bento rhythm. */
  items: z
    .array(bentoItemSchema)
    .default([
      { title: 'Motion identity', caption: 'One consistent feel across every component.', colSpan: 2, rowSpan: 1, accent: false },
      { title: 'Render', value: '4K', caption: 'Deterministic, frame-perfect.', colSpan: 1, rowSpan: 1, accent: true },
      { title: 'Components', value: '40+', caption: 'Copied into your project.', colSpan: 1, rowSpan: 1, accent: false },
      { title: 'Spring physics', caption: 'No overshoot. Calm by default.', colSpan: 2, rowSpan: 1, accent: false },
    ]),
  /** Number of grid columns. */
  columns: z.number().int().min(1).default(3),
  /** Gap between cells in px. */
  gap: z.number().default(20),
  /** Overall grid width in px. */
  width: z.number().default(960),
  /** Inner padding of each cell in px. */
  padding: z.number().default(28),
  /** Frames before the first cell enters. */
  delay: z.number().int().min(0).default(0),
  /** Frames between successive cells rising in. House stagger is 4. */
  stagger: z.number().int().min(0).default(4),
  /** Base title font size in px. Wins over `size` if both are passed. */
  fontSize: z.number().default(30),
  /** Semantic typography role for the title — resolves to canvas-aware pixels via the smaller canvas dimension. `fontSize` wins when both are passed. */
  size: sizeRoleSchema.optional(),
  /** Title color. Defaults to `--onda-text`. */
  color: z.string().default('var(--onda-text, #F2F2F4)'),
  /** Caption color. Defaults to `--onda-dim`. */
  captionColor: z.string().default('var(--onda-dim, #8E8E98)'),
  /** Accent color for the earned `accent` cell. Defaults to `--onda-accent`. */
  accentColor: z.string().default('var(--onda-accent, #D96B82)'),
  /** Onda display font for titles and values. */
  fontFamily: z.string().default('var(--onda-font-display, "Clash Display", sans-serif)'),
  /** Where on the canvas this sits. Region (`'center'`, `'upper-third'`, ...) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link BentoGrid}. */
export type BentoGridProps = z.infer<typeof bentoGridSchema>;

# BentoGrid

A data-driven bento layout: a CSS grid of glass `Surface` cards with varying column/row spans, driven entirely by an `items` array. Each cell rises and fades in on the house spring, staggered left-to-right (4-frame default), so the grid assembles as one calm cascade rather than popping all at once. Cells carry an optional large `value`, a `title`, and a `caption`; the single `accent` cell earns the rose. Renders a complete, premium bento with zero props.

## Props

| Prop | Type | Default | Notes |
| --- | --- | --- | --- |
| `items` | `BentoItem[]` | sample 4-card set | Each: `title`, optional `value` / `caption`, `colSpan` (1), `rowSpan` (1), `accent` (false). |
| `columns` | `number` | `3` | Grid column count. |
| `gap` | `number` | `20` | Gap between cells in px. |
| `width` | `number` | `960` | Overall grid width in px. |
| `padding` | `number` | `28` | Inner padding of each cell. |
| `delay` | `number` | `0` | Frames before the first cell enters. |
| `stagger` | `number` | `4` | Frames between successive cells. |
| `fontSize` | `number` | `30` | Base title size; wins over `size`. |
| `size` | size role | — | Semantic role (`hero`…`caption`); resolves to canvas-aware px. |
| `color` | `string` | `#F2F2F4` | Title color. |
| `captionColor` | `string` | `#8E8E98` | Caption color. |
| `accentColor` | `string` | `#D96B82` | Earned-accent cell color. |
| `fontFamily` | `string` | Clash Display | Title / value font. |
| `placement` | region or `{x,y,anchor}` | — | Canvas placement. |

## Usage

```tsx
import { Composition } from 'remotion';
import { BentoGrid } from './components/onda/bento-grid/BentoGrid';

const FeatureBento = () => (
  <BentoGrid
    placement="center"
    columns={3}
    items={[
      { title: 'Motion identity', caption: 'One consistent feel.', colSpan: 2 },
      { title: 'Render', value: '4K', accent: true },
      { title: 'Components', value: '40+' },
      { title: 'Spring physics', caption: 'No overshoot.', colSpan: 2 },
    ]}
  />
);

export const BentoComposition = () => (
  <Composition
    id="FeatureBento"
    component={FeatureBento}
    durationInFrames={120}
    fps={30}
    width={1920}
    height={1080}
  />
);
```
